 private floorTex?:THREE.Texture; private evening=false; private keyLight?:THREE.SpotLight; private lampLight?:THREE.PointLight; private dust?:THREE.Points; private roomGroup?:THREE.Group; private roomWidth=14; private roomDepth=11; private roomShape:RoomShape='rectangle'; private roomShapeWidth=.55; private roomCrossbarDepth=.55; private saveTimer=0; private catalogCategory:Category|'all'='all'; private catalogQuery=''; private ambience=new Audio(`${import.meta.env.BASE_URL}assets/audio/room-memory-loop.mp3`);
 constructor(private canvas:HTMLCanvasElement){this.renderer=createRenderer(canvas);this.renderer.toneMappingExposure=1.12;this.camera.position.set(12,10,15);this.controls=new OrbitControls(this.camera,canvas);this.controls.target.set(0,2.3,0);this.controls.enableDamping=true;this.controls.minDistance=10;this.controls.maxDistance=32;this.controls.maxPolarAngle=Math.PI*.48;this.controls.minPolarAngle=.45;this.loadRoomSettings();this.createWorld();this.bindUI();this.bindTouchExtras();this.load();resizeRenderer(this.renderer,this.camera,1.7);this.publish()}
