 private bindTouchExtras(){document.querySelector('#smaller')?.addEventListener('click',()=>this.resizeSelected(-.1));document.querySelector('#larger')?.addEventListener('click',()=>this.resizeSelected(.1));const distance=()=>{const p=[...this.touches.values()];return p.length<2?0:Math.hypot(p[0].clientX-p[1].clientX,p[0].clientY-p[1].clientY)};this.canvas.addEventListener('pointerdown',e=>{if(e.pointerType!=='touch')return;this.touches.set(e.pointerId,e);if(this.touches.size===2&&this.selected){if(this.drag)this.pointerUp();this.checkpoint();this.pinchStart=distance();this.pinchScale=this.findData()?.scale??1;this.controls.enabled=false;e.stopImmediatePropagation();return}this.setPointer(e);this.ray.setFromCamera(this.pointer,this.camera);if(this.ray.intersectObjects([...this.items.values()],true).length){this.pointerDown(e);e.stopImmediatePropagation()}},true);this.canvas.addEventListener('pointermove',e=>{if(e.pointerType!=='touch')return;this.touches.set(e.pointerId,e);if(this.pinchStart&&this.selected){const d=this.findData();if(d){d.scale=THREE.MathUtils.clamp(this.pinchScale*distance()/this.pinchStart,.55,1.6);this.selected.scale.setScalar(d.scale)}e.stopImmediatePropagation()}else if(this.drag){this.pointerMove(e);e.stopImmediatePropagation()}},true);const finish=(e:PointerEvent)=>{this.touches.delete(e.pointerId);if(this.pinchStart){this.pinchStart=0;this.controls.enabled=true;this.changed()}else this.pointerUp()};window.addEventListener('pointerup',finish,true);window.addEventListener('pointercancel',finish,true);this.canvas.addEventListener('lostpointercapture',finish);window.addEventListener('blur',()=>{this.touches.clear();this.pinchStart=0;this.pointerUp();this.controls.enabled=true});document.addEventListener('visibilitychange',()=>{if(document.hidden){this.touches.clear();this.pinchStart=0;this.pointerUp();this.controls.enabled=true}})}
 private renderCatalog(cat:Category|'all'){this.catalogCategory=cat;const host=document.querySelector('#items')!;host.innerHTML='';const terms=this.catalogQuery.split(/\s+/).filter(Boolean);const matches=CATALOG.filter(x=>{const haystack=`${x.name} ${x.note} ${x.kind}`.toLowerCase();return(cat==='all'||x.category===cat)&&terms.every(term=>haystack.includes(term))});for(const x of matches){const b=document.createElement('button');b.className='item';b.innerHTML=`<span>${x.icon}</span>${x.name}<small>${x.note}</small>`;b.onclick=()=>{this.add(x);if(innerWidth<700)document.querySelector('#catalog')?.classList.add('closed')};host.appendChild(b)}const empty=document.querySelector<HTMLElement>('#no-results')!;empty.hidden=matches.length>0}
