 private ownerOf(o:THREE.Object3D){let owner=o;while(owner.parent&&!owner.userData.itemId)owner=owner.parent;return owner.userData.itemId?owner as THREE.Group:undefined}
 private supportTop(g:THREE.Group){const d=this.data.find(x=>x.id===g.userData.itemId);return g.position.y+(SUPPORT_HEIGHTS[d?.kind??'']??new THREE.Box3().setFromObject(g).max.y-g.position.y)*(d?.scale??1)}
 private pointerDown(e:PointerEvent){if((e.target as HTMLElement)!==this.canvas)return;this.setPointer(e);this.ray.setFromCamera(this.pointer,this.camera);const hits=this.ray.intersectObjects([...this.items.values()],true);if(hits.length){const g=this.ownerOf(hits[0].object);if(!g)return;this.select(g);this.checkpoint();this.drag=true;this.controls.enabled=false;const d=this.data.find(x=>x.id===g.userData.itemId);this.dragHeight=d?.supportId?0:g.position.y;const hit=new THREE.Vector3();this.ray.ray.intersectPlane(new THREE.Plane(new THREE.Vector3(0,1,0),-this.dragHeight),hit);this.dragOffset.copy(g.position).sub(hit);this.canvas.setPointerCapture(e.pointerId)}else this.select(undefined)}
 private pointerMove(e:PointerEvent){if(!this.drag||!this.selected)return;this.setPointer(e);this.ray.setFromCamera(this.pointer,this.camera);const d=this.findData();if(!d)return;const oldX=d.x,oldZ=d.z;let support:THREE.Group|undefined;if(!FLOOR_ONLY_KINDS.has(d.kind)){for(const h of this.ray.intersectObjects([...this.items.values()].filter(g=>g!==this.selected),true)){const candidate=this.ownerOf(h.object);const candidateData=this.data.find(x=>x.id===candidate?.userData.itemId);if(candidate&&candidateData&&SUPPORT_KINDS.has(candidateData.kind)){support=candidate;break}}}if(support){const top=this.supportTop(support);const plane=new THREE.Plane(new THREE.Vector3(0,1,0),-top);const hit=new THREE.Vector3();if(this.ray.ray.intersectPlane(plane,hit)){const p=this.clampToRoom(this.selected,hit.x,hit.z);d.x=p.x;d.z=p.z;d.y=top+.025;d.supportId=support.userData.itemId}}else{const hit=new THREE.Vector3();if(this.ray.ray.intersectPlane(new THREE.Plane(new THREE.Vector3(0,1,0),-this.dragHeight),hit)){hit.add(this.dragOffset);const p=this.clampToRoom(this.selected,hit.x,hit.z);d.x=p.x;d.z=p.z;d.y=this.dragHeight;d.supportId=undefined}}this.selected.position.set(d.x,d.y??0,d.z);if(SUPPORT_KINDS.has(d.kind)){const dx=d.x-oldX,dz=d.z-oldZ;for(const child of this.data.filter(x=>x.supportId===d.id)){child.x+=dx;child.z+=dz;child.y=this.supportTop(this.selected)+.025;const childGroup=this.items.get(child.id);if(childGroup)childGroup.position.set(child.x,child.y,child.z)}}document.querySelector('#prompt')!.textContent=d.supportId?'Release to place on top.':this.dragHeight?`Moving at height ${this.dragHeight.toFixed(1)}.`:'Move it anywhere in the room.'}
